// Helper function to check if a rune is a vowel
func isVowel(r rune) bool {
	return r == 'a' || r == 'e' || r == 'i' || r == 'o' || r == 'u'
}

// VowelInfo stores necessary data for sorting a specific vowel
type VowelInfo struct {
	Char       rune
	Count      int
	FirstIndex int
}

// solve implements the required logic
func solve(s string) string {
	// 1. Collect statistics: Count and First Index
	counts := make(map[rune]int)
	firstIndex := make(map[rune]int)

	for i, r := range s {
		if isVowel(r) {
			counts[r]++
			if _, ok := firstIndex[r]; !ok {
				firstIndex[r] = i
			}
		}
	}

	// 2. Gather unique vowel information
	var vowelInfos []VowelInfo
	for r := range counts {
		vowelInfos = append(vowelInfos, VowelInfo{
			Char:       r,
			Count:      counts[r],
			FirstIndex: firstIndex[r],
		})
	}

	// 3. Sort the unique vowels
	sort.Slice(vowelInfos, func(i, j int) bool {
		a := vowelInfos[i]
		b := vowelInfos[j]

		// Primary criteria: Frequency (Non-increasing/Descending)
		if a.Count != b.Count {
			return a.Count > b.Count
		}
		// Secondary criteria: First appearance index (Ascending/Earlier first)
		return a.FirstIndex < b.FirstIndex
	})

	// 4. Create the replacement sequence of all vowels
	var replacementVowels []rune
	for _, info := range vowelInfos {
		for k := 0; k < info.Count; k++ {
			replacementVowels = append(replacementVowels, info.Char)
		}
	}

	// 5. Reconstruct the string
	result := make([]rune, 0, len(s))
	vowelSeqIdx := 0

	for _, r := range s {
		if !isVowel(r) {
			// Consonants remain in place
			result = append(result, r)
		} else {
			// Vowel is replaced by the next vowel in the sorted sequence
			result = append(result, replacementVowels[vowelSeqIdx])
			vowelSeqIdx++
		}
	}

	return string(result)
}
